Handle Missing Data
Return None rather than raising exceptions:
# Good: Defensive
@transform
def safe_get(ctx: Context, field: str) -&gt; str | None:
    try:
        return ctx.node[field]
    except (KeyError, TypeError):
        return None

# Bad: May raise
@transform
def unsafe_get(ctx: Context, field: str) -&gt; str:
    return ctx.node[field]  # Raises if missing!

Type Hints
Use type hints for better IDE support:
@transform
def parse_date(ctx: Context, field: str, format: str = "%Y-%m-%d") -&gt; str | None:
    """Parse and reformat a date string."""
    from datetime import datetime

    value = ctx.node.get(field)
    if not value:
        return None

    try:
        dt = datetime.strptime(value, format)
        return dt.isoformat()
    except ValueError:
        return None

Fail Fast Mode
Stop processing immediately on first error:

from etielle import etl, Field, TempField, get

data = {"users": [{"id": None, "name": "Bob"}]}

try:
    result = (
        etl(data, errors="fail_fast")
        .goto("users").each()
        .map_to(table="users", fields=[
            Field("name", get("name")),
            TempField("id", get("id"))
        ])
        .run()
    )
except ValueError as e:
    print(f"Pipeline failed: {e}")

Error Structure
Errors are keyed by table name, then by row key:
result.errors = {
    "table_name": {
        ("row", "key"): ["error message 1", "error message 2"],
        ("another", "key"): ["error message"]
    }
}

Inspecting Errors

from etielle import etl, Field, TempField, get
from pydantic import BaseModel, field_validator

class User(BaseModel):
    name: str

    @field_validator("name")
    @classmethod
    def name_not_empty(cls, v):
        if not v or not v.strip():
            raise ValueError("Name cannot be empty")
        return v

data = {
    "users": [
        {"id": "u1", "name": "Alice"},
        {"id": "u2", "name": ""},      # Invalid: empty name
        {"id": "u3", "name": "Carol"}
    ]
}

result = (
    etl(data)
    .goto("users").each()
    .map_to(table=User, fields=[
        Field("name", get("name")),
        TempField("id", get("id"))
    ])
    .run()
)

# Check for errors
if result.errors:
    for table_name, table_errors in result.errors.items():
        for row_key, messages in table_errors.items():
            print(f"{table_name}[{row_key}]: {messages}")

