parent_key(depth=1) - Parent’s dict key
Gets the dict key from a parent iteration.

from etielle import etl, Field, TempField, get, parent_key
import json

data = {
    "categories": {
        "fruits": ["apple", "banana"],
        "vegetables": ["carrot", "broccoli"]
