parent_index(depth=1) - Parent’s list index
Gets the list index from a parent iteration.

from etielle import etl, Field, TempField, get, parent_index, index, concat, literal
import json

data = {
    "rows": [
        ["a", "b", "c"],
        ["d", "e", "f"]
    ]
